 19→export function createWallDrawHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled, activePhaseId }) {
 20→  return {
 21→    onMouseDown(modelPos, e, toolState) {
 22→      if (e.button !== 0) return;
 23→
 24→      const floor = getFloor(activeFloorId);
 25→      if (!floor) return;
 26→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
 27→      const shiftHeld = e.shiftKey;
 28→
 29→      let snapped = modelPos;
 30→      let attachment = null;
 31→      if (snapEnabled) {
 32→        const snapResult = snapWallEndpoint(modelPos, {
 33→          walls: floor.walls,
 34→          columns: floor.columns || [],
 35→          snapDist: snapDistModel,
 36→          chainStart: toolState.chainStart,
 37→          otherPoint: toolState.start,
 38→        });
 39→        if (snapResult) {
 40→          snapped = { ...snapResult.point };
 41→          attachment = snapResult.attachment;
 42→        }
 43→      }
 44→      if (shiftHeld && toolState.start) {
 45→        snapped = constrainAngle(toolState.start, snapped, true);
 46→        attachment = null;
 47→      }
 48→
 49→      if (!toolState.start) {
 50→        // First click: set start
 51→        editorDispatch({
 52→          type: 'UPDATE_TOOL_STATE',
 53→          payload: { start: snapped, chainStart: snapped, startAttachment: attachment, preview: null },
 54→        });
 55→      } else {
 56→        // Second+ click: create wall and chain
 57→        const endPt = snapped;
 58→
 59→        const len = distance(toolState.start, endPt);
 60→        if (len < MIN_WALL_LENGTH) return;
 61→
 62→        const wall = createWall(toolState.start, endPt, undefined, {
 63→          startAttachment: toolState.startAttachment || null,
 64→          endAttachment: attachment,
 65→        });
 66→        wall.phaseId = activePhaseId || null;
 67→        dispatch({ type: 'WALL_ADD', floorId: activeFloorId, wall });
 68→
 69→        // Check if we snapped back to chain start (close loop)
 70→        if (toolState.chainStart && distance(endPt, toolState.chainStart) < snapDistModel) {
 71→          editorDispatch({
 72→            type: 'UPDATE_TOOL_STATE',
 73→            payload: { start: null, chainStart: null, startAttachment: null, preview: null },
 74→          });
 75→        } else {
 76→          // Chain: end becomes new start
 77→          editorDispatch({
 78→            type: 'UPDATE_TOOL_STATE',
 79→            payload: { start: endPt, startAttachment: attachment, preview: null },
 80→          });
 81→        }
 82→      }
 83→    },
 84→
 85→    onMouseMove(modelPos, e, toolState) {
 86→      if (!toolState.start) return;
 87→      let preview = modelPos;
 88→
 89→      const floor = getFloor(activeFloorId);
 90→      if (!floor) return;
 91→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
 92→      if (snapEnabled) {
 93→        const snapResult = snapWallEndpoint(modelPos, {
 94→          walls: floor.walls,
 95→          columns: floor.columns || [],
 96→          snapDist: snapDistModel,
 97→          chainStart: toolState.chainStart,
 98→          otherPoint: toolState.start,
 99→        });
100→        if (snapResult) preview = { ...snapResult.point };
101→      }
102→      if (e.shiftKey) {
103→        preview = constrainAngle(toolState.start, preview, true);
104→      }
105→
106→      editorDispatch({
107→        type: 'UPDATE_TOOL_STATE',
108→        payload: { preview },
109→      });
110→    },
111→
112→    onDoubleClick(modelPos, e, toolState) {
113→      // Finish chain
114→      editorDispatch({
115→        type: 'UPDATE_TOOL_STATE',
116→        payload: { start: null, chainStart: null, startAttachment: null, preview: null },
117→      });
118→    },
119→
120→    onKeyDown(e, toolState) {
121→      if (e.key === 'Escape') {
122→        editorDispatch({
123→          type: 'UPDATE_TOOL_STATE',
124→          payload: { start: null, chainStart: null, startAttachment: null, preview: null },
125→        });
126→      }
127→    },
128→
129→    getCursor(toolState) {
130→      return 'crosshair';
131→    },
132→  };
133→}
