 42→export function createDoorPlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId, activePhaseId }) {
 43→  return {
 44→    onMouseMove(modelPos, e, toolState) {
 45→      const floor = getFloor(activeFloorId);
 46→      if (!floor) return;
 47→      const wall = findNearestWall(modelPos, floor.walls);
 48→
 49→      if (wall) {
 50→        const offset = projectPointOnWall(wall, modelPos);
 51→        const clampedOffset = clampWallOpeningOffset(wallLength(wall), DOOR_WIDTH, offset);
 52→        const blocked = overlapsExisting(wall.id, clampedOffset, DOOR_WIDTH, floor.doors, floor.windows);
 53→
 54→        editorDispatch({
 55→          type: 'UPDATE_TOOL_STATE',
 56→          payload: {
 57→            previewWallId: wall.id,
 58→            previewOffset: clampedOffset,
 59→            previewBlocked: blocked,
 60→            openDirection: toolState.openDirection || 'left',
 61→          },
 62→        });
 63→      } else {
 64→        editorDispatch({
 65→          type: 'UPDATE_TOOL_STATE',
 66→          payload: { previewWallId: null, previewOffset: null, previewBlocked: false, openDirection: toolState.openDirection || 'left' },
 67→        });
 68→      }
 69→    },
 70→
 71→    onMouseDown(modelPos, e, toolState) {
 72→      if (e.button !== 0) return;
 73→      if (!toolState.previewWallId || toolState.previewBlocked) return;
 74→
 75→      const openDir = toolState.openDirection || 'left';
 76→      const door = createDoor(toolState.previewWallId, toolState.previewOffset, DOOR_WIDTH, openDir);
 77→      door.phaseId = activePhaseId || null;
 78→      dispatch({ type: 'DOOR_ADD', floorId: activeFloorId, door });
 79→    },
 80→
 81→    onKeyDown(e, toolState) {
 82→      if (e.key === 'Escape') {
 83→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
 84→      }
 85→      if (e.key === 'f' || e.key === 'F') {
 86→        const flipped = toolState.openDirection === 'right' ? 'left' : 'right';
 87→        editorDispatch({
 88→          type: 'UPDATE_TOOL_STATE',
 89→          payload: { openDirection: flipped },
 90→        });
 91→      }
 92→    },
 93→
 94→    getCursor(toolState) {
 95→      if (!toolState.previewWallId || toolState.previewBlocked) return 'not-allowed';
 96→      return 'copy';
 97→    },
 98→  };
 99→}
