 13→function polygonArea(points) {
 14→  if (!points || points.length < 3) return 0;
 15→  let total = 0;
 16→  for (let index = 0; index < points.length; index += 1) {
 17→    const current = points[index];
 18→    const next = points[(index + 1) % points.length];
 19→    total += current.u * next.v - next.u * current.v;
 20→  }
 21→  return Math.abs(total) / 2;
 22→}
