 24→export function createDrawProfileHandler3d({
 25→  dispatch,
 26→  editorDispatch,
 27→  project,
 28→  activeAssemblyId,
 29→  partType,
 30→  snapEnabled,
 31→  drawingPlane,
 32→  inferenceCache,
