118→/**
119→ * Project a 3D point onto a plane, returning local (u, v) coordinates.
120→ */
121→export function projectToPlane(point3d, plane) {
122→  const dx = point3d.x - plane.origin.x;
123→  const dy = point3d.y - plane.origin.y;
124→  const dz = point3d.z - plane.origin.z;
125→  const u = dx * plane.uAxis.x + dy * plane.uAxis.y + dz * plane.uAxis.z;
126→  const v = dx * plane.vAxis.x + dy * plane.vAxis.y + dz * plane.vAxis.z;
127→  return { u, v };
128→}
129→
130→/**
131→ * Convert local (u, v) on a plane back to 3D world coordinates.
132→ */
133→export function planeLocalToWorld(u, v, plane) {
134→  return {
135→    x: plane.origin.x + u * plane.uAxis.x + v * plane.vAxis.x,
136→    y: plane.origin.y + u * plane.uAxis.y + v * plane.vAxis.y,
137→    z: plane.origin.z + u * plane.uAxis.z + v * plane.vAxis.z,
138→  };
139→}
140→
141→/**
142→ * Map a Three.js face normal (approximate) to a canonical face ID.
143→ * Three.js coords: x=domain x, y=domain z, z=domain y
144→ */
145→export function identifyFace(threeNormal) {
146→  const ax = Math.abs(threeNormal.x);
147→  const ay = Math.abs(threeNormal.y);
148→  const az = Math.abs(threeNormal.z);
149→
150→  if (ay >= ax && ay >= az) {
151→    return threeNormal.y > 0 ? '+z' : '-z'; // Three.js Y = domain Z
152→  }
153→  if (ax >= ay && ax >= az) {
154→    return threeNormal.x > 0 ? '+x' : '-x';
155→  }
156→  return threeNormal.z > 0 ? '+y' : '-y'; // Three.js Z = domain Y
157→}
