  3→const DEFAULT_NORMAL = { x: 0, y: 0, z: 1 };
  4→const DEFAULT_U_AXIS = { x: 1, y: 0, z: 0 };
  5→const DEFAULT_V_AXIS = { x: 0, y: 1, z: 0 };
