  7→function cloneVector(vector, fallback) {
  8→  return {
  9→    x: Number.isFinite(vector?.x) ? vector.x : fallback.x,
 10→    y: Number.isFinite(vector?.y) ? vector.y : fallback.y,
 11→    z: Number.isFinite(vector?.z) ? vector.z : fallback.z,
 12→  };
 13→}
 14→
 15→function normalizeVector(vector, fallback) {
 16→  const candidate = cloneVector(vector, fallback);
 17→  const length = Math.hypot(candidate.x, candidate.y, candidate.z) || 1;
 18→  return {
 19→    x: candidate.x / length,
 20→    y: candidate.y / length,
 21→    z: candidate.z / length,
 22→  };
 23→}
 24→
 25→function dedupeProfilePoints(points) {
 26→  const normalized = [];
 27→  for (const point of points || []) {
 28→    const candidate = {
 29→      u: Number.isFinite(point?.u) ? point.u : 0,
 30→      v: Number.isFinite(point?.v) ? point.v : 0,
 31→    };
 32→    const previous = normalized[normalized.length - 1];
 33→    if (previous && Math.hypot(candidate.u - previous.u, candidate.v - previous.v) < 0.001) {
 34→      continue;
 35→    }
 36→    normalized.push(candidate);
 37→  }
 38→
 39→  if (normalized.length > 2) {
 40→    const first = normalized[0];
 41→    const last = normalized[normalized.length - 1];
 42→    if (Math.hypot(first.u - last.u, first.v - last.v) < 0.001) {
 43→      normalized.pop();
 44→    }
 45→  }
 46→
 47→  return normalized;
 48→}
 49→
 50→export function clonePlaneDefinition(plane = {}) {
 51→  const normal = normalizeVector(plane.normal, DEFAULT_NORMAL);
 52→  const uAxis = normalizeVector(plane.uAxis, DEFAULT_U_AXIS);
 53→  const vAxis = normalizeVector(plane.vAxis, DEFAULT_V_AXIS);
 54→  return {
 55→    normal,
 56→    uAxis,
 57→    vAxis,
 58→    up: normalizeVector(plane.up, vAxis),
 59→    sourcePartId: plane.sourcePartId || null,
 60→    sourceFace: plane.sourceFace || null,
 61→  };
 62→}
 63→
 64→export function getSolidPlane(part) {
 65→  return {
 66→    origin: {
 67→      x: Number.isFinite(part?.position?.x) ? part.position.x : 0,
 68→      y: Number.isFinite(part?.position?.y) ? part.position.y : 0,
 69→      z: Number.isFinite(part?.position?.z) ? part.position.z : 0,
 70→    },
 71→    ...clonePlaneDefinition(part?.plane),
 72→  };
 73→}
 74→
 75→export function normalizeSolidProfile(points) {
 76→  const profile = dedupeProfilePoints(points);
 77→  if (profile.length >= 3) return profile;
 78→  return [
 79→    { u: 0, v: 0 },
 80→    { u: 600, v: 0 },
 81→    { u: 600, v: 400 },
 82→    { u: 0, v: 400 },
 83→  ];
 84→}
 85→
 86→export function getSolidBaseVertices(part) {
 87→  const plane = getSolidPlane(part);
 88→  const profilePoints = normalizeSolidProfile(part.profilePoints);
 89→  return profilePoints.map((point) => planeLocalToWorld(point.u, point.v, plane));
 90→}
 91→
 92→export function getSolidVertices(part) {
 93→  const base = getSolidBaseVertices(part);
 94→  const plane = getSolidPlane(part);
 95→  const depth = Number.isFinite(part?.extrusionDepth) ? part.extrusionDepth : 120;
 96→  const top = base.map((point) => ({
 97→    x: point.x + plane.normal.x * depth,
 98→    y: point.y + plane.normal.y * depth,
 99→    z: point.z + plane.normal.z * depth,
100→  }));

